DELETE FROM `command` WHERE `name` IN (
    'smartstone',
    'smartstone unlock service',
    'smartstone unlock account',
    'smartstone reload',
    'smartstone cooldowns',
    'smartstone lookup',
    'smartstone lookup pets',
    'smartstone lookup costumes',
    'smartstone lookup allpets',
    'smartstone use',
    'smartstone use costume',
    'smartstone use pet',
    'smartstone toggle',
    'smartstone toggle costumes',
    'smartstone toggle forms',
    'smartstone toggle minions',
    'smartstone token',
    'smartstone token claim',
    'smartstone token grant',
    'smartstone token list',
    'smartstone token revoke'
);

INSERT INTO `command` (`name`, `security`, `help`) VALUES
('smartstone',                 0, 'Syntax: .smartstone\nAdds the Smartstone item to your inventory if you do not already have one.'),
('smartstone unlock service',  1, 'Syntax: .smartstone unlock service $player $serviceType $id $add\nGrants or revokes access to a smartstone service for a player.\n$serviceType: 0=Companion, 1=Combat Pet, 2=Costume, 6=Aura, 7=Vehicle.\n$id: The service ID (CreatureId for pets, costume Id for costumes).\n$add: 1 to grant, 0 to revoke.'),
('smartstone unlock account',  1, 'Syntax: .smartstone unlock account $account $serviceType $id $add\nGrants or revokes an account-wide smartstone service for an account, without needing to select a character.\n$serviceType: 2=Costume, 9=Perk.\n$id: The service ID (costume Id for costumes, perk Id for perks).\n$add: 1 to grant, 0 to revoke.\nFor per-character services (pets, auras, vehicles) use .smartstone unlock service instead.'),
('smartstone reload',          3, 'Syntax: .smartstone reload\nReloads all smartstone data from the database.'),
('smartstone cooldowns',       0, 'Syntax: .smartstone cooldowns [$player]\nShows active costume cooldowns.\nRegular players can only check their own cooldowns.\nGameMasters and above can check any player''s cooldowns, including offline players.'),
('smartstone lookup',          0, 'Syntax: .smartstone lookup [pets|costumes|allpets]\nLookup commands for browsing available smartstone services.'),
('smartstone lookup pets',     0, 'Syntax: .smartstone lookup pets [$filter]\nLists all companion and combat pets currently available to you.\nOptionally filters results by name. Shows the ID used with .smartstone use pet.'),
('smartstone lookup costumes', 0, 'Syntax: .smartstone lookup costumes [$filter]\nLists all costumes currently available to you.\nOptionally filters results by name. Shows the ID used with .smartstone use costume.'),
('smartstone lookup allpets',  2, 'Syntax: .smartstone lookup allpets [$filter]\nLists every pet loaded in the system regardless of unlock status.\nOptionally filters results by name. Shows the ID used with .smartstone unlock service.'),
('smartstone use',             0, 'Syntax: .smartstone use [costume|pet]\nCommands to apply a smartstone costume or summon a pet.'),
('smartstone use costume',     0, 'Syntax: .smartstone use costume $id\nApplies the costume with the given ID if you have access to it.\nUse .smartstone lookup costumes to find available IDs.'),
('smartstone use pet',         0, 'Syntax: .smartstone use pet $id\nSummons the companion or combat pet with the given ID if you have access to it.\nUse .smartstone lookup pets to find available IDs.'),
('smartstone toggle',          0, 'Syntax: .smartstone toggle [costumes|forms|minions]\nView preferences for hiding other players'' Smartstone display overrides.'),
('smartstone toggle costumes', 0, 'Syntax: .smartstone toggle costumes\nToggles whether you see other players'' Smartstone costumes.'),
('smartstone toggle forms',    0, 'Syntax: .smartstone toggle forms\nToggles whether you see other players'' Smartstone druid / shaman form skins.'),
('smartstone toggle minions',  0, 'Syntax: .smartstone toggle minions\nToggles whether you see other players'' Smartstone warlock-pet / feral-spirit skins.'),
('smartstone token',         0, 'Syntax: .smartstone token [claim|grant|list|revoke]\nManage one-shot character-service tokens (rename, faction, race, appearance).'),
('smartstone token claim',   0, 'Syntax: .smartstone token claim $id\nClaims one of your account''s tokens on the current character.\nThe service applies at the character selection screen. Find IDs in your Smartstone (Character > Tokens) or the login reminder.'),
('smartstone token grant',   1, 'Syntax: .smartstone token grant $account $type\nGrants a token to an account.\n$type: 1=Name Change, 2=Faction Change, 3=Race Change, 4=Appearance Change.'),
('smartstone token list',    1, 'Syntax: .smartstone token list $account [all]\nLists an account''s unclaimed tokens and their IDs.\nAdd "all" to also list claimed tokens, with who claimed each and when.'),
('smartstone token revoke',  1, 'Syntax: .smartstone token revoke $id\nRemoves an unclaimed token by ID. Already-claimed tokens are preserved for audit.');
